Here's how to handle draft persistence using MAUI's app lifecycle events:

**1. In `App.xaml.cs`, hook the lifecycle events:**

```csharp
public partial class App : Application
{
    public App()
    {
        InitializeComponent();
        MainPage = new NavigationPage(new NotePage());
    }

    protected override Window CreateWindow(IActivationState? activationState)
    {
        var window = base.CreateWindow(activationState);

        window.Deactivated += (s, e) =>
            WeakReferenceMessenger.Default.Send(new AppBackgroundMessage());

        window.Activated += (s, e) =>
            WeakReferenceMessenger.Default.Send(new AppForegroundMessage());

        return window;
    }
}

// Simple message types
public class AppBackgroundMessage { }
public class AppForegroundMessage { }
```

**2. In your `NotePage.xaml.cs`, respond to the messages:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();
        RestoreDraft();

        WeakReferenceMessenger.Default.Register<AppBackgroundMessage>(this, (r, m) =>
            SaveDraft());

        WeakReferenceMessenger.Default.Register<AppForegroundMessage>(this, (r, m) =>
            RestoreDraft());
    }

    private void SaveDraft()
    {
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    private void RestoreDraft()
    {
        NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }

    protected override void OnDisappearing()
    {
        base.OnDisappearing();
        WeakReferenceMessenger.Default.UnregisterAll(this);
    }
}
```

**3. Required NuGet package:**

```
CommunityToolkit.Mvvm
```

This gives you `WeakReferenceMessenger`. Add the using:

```csharp
using CommunityToolkit.Mvvm.Messaging;
```

**Key points:**

- **`Preferences`** — built-in MAUI key-value store, ideal for small text drafts
- **`Window.Deactivated`** fires when the app backgrounds; `Activated` when it returns
- **`WeakReferenceMessenger`** decouples lifecycle from your page (no static references)
- Call `ClearDraft()` after a successful save to avoid restoring stale data
- For large text, swap `Preferences` for `File.WriteAllTextAsync` to a file in `FileSystem.AppDataDirectory`
